import React, { useState, useEffect, useRef } from 'react';
import logo from './logo.svg';
import './App.css';

function App() {
  const [displayText, setDisplayText] = useState('');
  const terminalRef = useRef(null);
  const [cursorVisible, setCursorVisible] = useState(false);
  const [underlineVisible, setUnderlineVisible] = useState(false);
  const [underlineIndex, setUnderlineIndex] = useState(-1);

  useEffect(() => {
    const terminalOutputs = [
      'Windows PowerShell',
      'Copyright (C) Microsoft Corporation. All rights reserved.',
      '',
      'PS C:\\users\\Admin> ',
    ];

    const textToType = 'My name is Nathaniel';
    let currentTextIndex = 0;

    const typeText = () => {
      if (currentTextIndex < textToType.length) {
        const currentTypedText = textToType.substring(0, currentTextIndex + 1);
        const textWithCursor = terminalOutputs[3] + currentTypedText;
        setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + textWithCursor);
        currentTextIndex++;
        setTimeout(typeText, 200); // Delay between each letter
      } else {
        setCursorVisible(true);
        setTimeout(() => {
          setUnderlineVisible(true);
          setUnderlineIndex(terminalOutputs[3].length + 'My name is '.length); // Index where 'Nathaniel' starts
        }, 1000); // Delay before showing the underline
      }
    };

    setDisplayText(terminalOutputs.join('\n'));

    terminalRef.current.scrollTop = terminalRef.current.scrollHeight;

    setTimeout(typeText, 2000); // Delay before starting to type

  }, []);

  useEffect(() => {
    let cursorInterval;
    if (cursorVisible) {
      cursorInterval = setInterval(() => {
        setDisplayText((prevText) => {
          if (prevText.endsWith('|')) {
            return prevText.slice(0, -1);
          } else {
            return prevText + '|';
          }
        });
      }, 500); // Cursor blink interval
    }

    return () => {
      clearInterval(cursorInterval);
    };
  }, [cursorVisible]);

  const underlineStyle = {
    textDecoration: 'underline',
    color: 'red',
    fontWeight: 'bold',
  };

  const underlineBarStyle = {
    position: 'absolute',
    bottom: '-2px',
    left: `${underlineIndex * 10}px`, // Adjust based on the width of the text
    width: '80px', // Adjust based on the width of the text
    height: '2px',
    backgroundColor: 'red',
  };

  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <div className="terminal" ref={terminalRef}>
          <pre>
            {displayText}
            {underlineVisible && (
              <span style={underlineStyle}>
                Nathaniel
                <span style={underlineBarStyle}></span>
              </span>
            )}
          </pre>
        </div>
      </header>
    </div>
  );
}

export default App;
